static int wc_preclass_confidence_token_level(const char* confidence)
{
	if (!confidence || !*confidence)
		return 0;
	if (strcmp(confidence, "high") == 0)
		return 3;
	if (strcmp(confidence, "medium") == 0)
		return 2;
	if (strcmp(confidence, "low") == 0)
		return 1;
	return 0;
}

